import React from "react";

/**
 * StickyLogo
 *
 * SVG-based React component that reproduces the "Reverse Generation" logo.
 *
 * ── Font identification ──────────────────────────────────────────────────────
 *
 * "Reverse"    → High-contrast Didone display serif. The ultra-thick verticals,
 *                ultra-thin hairline horizontals, and — most distinctively — the
 *                curled/flourished descending leg on the capital "R" all point to
 *                a Victorian Bodoni variant, most likely **"Bodoni Moda"** (the
 *                Google Fonts version of the classic Bodoni Poster display cut)
 *                or **ITC Bodoni Seventy-Two**. The decorative R-leg is a known
 *                feature of several "ornamental" or "swash" Bodoni families.
 *
 * "Generation" → Lighter, slightly condensed serif in a classical Bodoni Book
 *                or Garamond weight, letter-spaced, centered below.
 *                Closest free match: **"Cormorant Garamond"** or **"IM Fell English"**.
 *
 * ── Implementation approach ──────────────────────────────────────────────────
 *
 * Because the "Reverse" wordmark uses swash/ornamental glyphs (especially the
 * curled R) that may not render via a standard font weight, we embed the Google
 * Font "Bodoni Moda" with `font-style: italic` (the italic cut carries the
 * decorative R leg), then use SVG <text> elements for both lines. This produces
 * a true vector logo that:
 *  • scales to any size without pixelation
 *  • matches the original letterforms as closely as possible
 *  • has zero raster image dependency
 *
 * If you need the exact proprietary font (ITC Bodoni Seventy-Two Swash), load it
 * via @font-face in your global CSS and update fontFamily below accordingly.
 */

interface StickyLogoProps {
  /** Width of the rendered logo. Height scales proportionally (default: 220px). */
  width?: number | string;
  /** Fill color (default: #000000) */
  color?: string;
  className?: string;
  style?: React.CSSProperties;
}

